use std::sync::{Arc, Mutex};

// Simplified buffer allocation
struct Buffer {
    data: Vec<u8>,
    locks: Mutex<bool>,
}

impl Buffer {
    fn new(size: usize) -> Arc<Buffer> {
        let data = vec![0; size];
        Arc::new(Buffer { data, locks: Mutex::new(false) })
    }

    fn lock(&self) -> Arc<Mutex<bool>> {
        Arc::clone(&self.locks).lock().unwrap()
    }

    fn release(&self) {
        self.locks.lock().unwrap().unwrap();
    }
}
